// Neon Darts VR — Main entry point
import {
  World,
  PanelUI,
  PanelDocument,
  UIKitDocument,
  Follower,
  FollowBehavior,
  ScreenSpace,
  Mesh,
  Group,
  BoxGeometry,
  SphereGeometry,
  CylinderGeometry,
  ConeGeometry,
  TorusGeometry,
  RingGeometry,
  PlaneGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  LineBasicMaterial,
  Color,
  Vector3,
  Quaternion,
  Euler,
  Matrix4,
  Fog,
  AmbientLight,
  PointLight,
  DirectionalLight,
  BufferGeometry,
  Float32BufferAttribute,
  EdgesGeometry,
  LineSegments,
  AdditiveBlending,
  DoubleSide,
  BackSide,
  FrontSide,
  MathUtils,
  Raycaster,
  Vector2,
  Object3D,
  CircleGeometry,
} from '@iwsdk/core';

import { createDartboard, BOARD_SEGMENTS, getScoreForPosition, ScoreResult } from './dartboard';
import { DartManager } from './darts';
import { AudioManager } from './audio';
import { createEnvironment } from './environment';
import { GameManager, GameMode, GameState } from './game';
import { AIOpponent, AIDifficulty } from './ai';
import { UIManager } from './ui';
import { AchievementManager } from './achievements';
import { StatsTracker } from './stats';
import { EffectsManager } from './effects';

async function main() {
  const container = document.getElementById('app') as HTMLDivElement;

  const world = await World.create(container, {
    xr: { offer: 'once' as const },
    input: { canvasPointerEvents: true },
    features: {
      grabbing: true,
      locomotion: false,
      physics: true,
      spatialUI: true,
    },
    render: {
      near: 0.01,
      far: 200,
      camera: { position: [0, 1.6, 0], lookAt: [0, 1.73, -2.37] },
    },
  } as any);

  // Audio
  const audio = new AudioManager();

  // Stats
  const stats = new StatsTracker();

  // Effects
  const effects = new EffectsManager(world);

  // Achievements
  const achievements = new AchievementManager(stats);

  // Create environment
  createEnvironment(world);

  // Create dartboard at standard distance (2.37m away, center at 1.73m height)
  const boardGroup = createDartboard(world);
  boardGroup.position.set(0, 1.73, -2.37);
  world.scene.add(boardGroup);

  // Dart manager
  const dartManager = new DartManager(world, boardGroup, audio, effects);

  // Game manager
  const game = new GameManager(stats, achievements, audio);

  // AI opponent
  const ai = new AIOpponent();

  // UI manager
  const ui = new UIManager(world, game, dartManager, audio, achievements, stats, ai);

  // Input state
  let isCharging = false;
  let chargeStart = 0;
  let aimX = 0;
  let aimY = 0;
  const maxCharge = 1500; // ms for full power
  let mouseX = 0;
  let mouseY = 0;
  let isPointerLocked = false;

  // Browser mouse input
  const canvas = container.querySelector('canvas');
  if (canvas) {
    canvas.addEventListener('mousedown', (e: MouseEvent) => {
      if (e.button === 0 && game.state === GameState.Playing && !game.isAITurn()) {
        if (dartManager.canThrow()) {
          isCharging = true;
          chargeStart = performance.now();
          ui.showPowerBar(true);
        }
      }
    });

    canvas.addEventListener('mouseup', (e: MouseEvent) => {
      if (e.button === 0 && isCharging) {
        const chargeDuration = Math.min(performance.now() - chargeStart, maxCharge);
        const power = chargeDuration / maxCharge;
        dartManager.throwDart(aimX, aimY, power);
        isCharging = false;
        ui.showPowerBar(false);
        ui.updatePower(0);
      }
    });

    canvas.addEventListener('mousemove', (e: MouseEvent) => {
      if (game.state === GameState.Playing) {
        // Map mouse position to aim coordinates on the board
        const rect = canvas.getBoundingClientRect();
        mouseX = ((e.clientX - rect.left) / rect.width) * 2 - 1;
        mouseY = -((e.clientY - rect.top) / rect.height) * 2 + 1;

        // Raycaster to find board intersection
        const raycaster = new Raycaster();
        raycaster.setFromCamera(new Vector2(mouseX, mouseY), (world as any).camera || (world as any).renderer?.xr?.getCamera?.() || world.scene.children.find((c: any) => c.isCamera));

        // Use a simple plane at the board position for aim
        const boardPlane = new PlaneGeometry(1, 1);
        const boardMesh = new Mesh(boardPlane, new MeshBasicMaterial({ visible: false }));
        boardMesh.position.copy(boardGroup.position);
        world.scene.add(boardMesh);

        const intersects = raycaster.intersectObject(boardMesh);
        if (intersects.length > 0) {
          const point = intersects[0].point;
          aimX = point.x - boardGroup.position.x;
          aimY = point.y - boardGroup.position.y;
        }
        world.scene.remove(boardMesh);
        boardMesh.geometry.dispose();
      }
    });
  }

  // Keyboard input
  window.addEventListener('keydown', (e: KeyboardEvent) => {
    switch (e.key) {
      case 'Escape':
        if (game.state === GameState.Playing) {
          game.setState(GameState.Paused);
          ui.showPanel('pause');
        } else if (game.state === GameState.Paused) {
          game.setState(GameState.Playing);
          ui.showPanel('hud');
        }
        break;
    }
  });

  // Dart hit callback
  dartManager.onDartHit = (result: ScoreResult) => {
    game.recordThrow(result);
    ui.updateGameState();
    effects.spawnHitParticles(
      new Vector3(
        boardGroup.position.x + result.x,
        boardGroup.position.y + result.y,
        boardGroup.position.z + 0.02
      ),
      result.multiplier === 3 ? '#ff00ff' : result.multiplier === 2 ? '#00ff00' : '#00ffff'
    );

    // Check achievements
    achievements.checkAll(game, result);

    // Check if turn is over (3 darts thrown)
    if (game.dartsThisRound >= 3) {
      setTimeout(() => {
        game.endTurn();
        dartManager.clearDarts();

        if (game.isGameOver()) {
          game.setState(GameState.GameOver);
          ui.showPanel('gameover');
          audio.playGameOver(game.getWinner() === 1);
          stats.recordGame(game.mode, game.getWinner() === 1);
          achievements.checkAll(game, null);
        } else if (game.isAITurn()) {
          // AI throws
          setTimeout(() => performAITurn(), 800);
        }

        ui.updateGameState();
      }, 600);
    }
  };

  // AI turn
  function performAITurn() {
    if (!game.isAITurn() || game.state !== GameState.Playing) return;

    const target = ai.getTarget(game);
    const { x, y } = ai.applyNoise(target.x, target.y);

    dartManager.throwDart(x, y, 0.7 + Math.random() * 0.2);

    // AI throws 3 darts with delays
    if (game.dartsThisRound < 2) {
      setTimeout(() => {
        if (game.isAITurn() && game.state === GameState.Playing && game.dartsThisRound < 3) {
          performAITurn();
        }
      }, 1200);
    }
  }

  // XR input handling
  let xrCharging = false;
  let xrChargeStart = 0;

  // Update loop
  let lastTime = 0;
  function update(time: number) {
    const dt = Math.min((time - lastTime) / 1000, 0.05);
    lastTime = time;

    // Update charging power bar
    if (isCharging) {
      const elapsed = Math.min(performance.now() - chargeStart, maxCharge);
      ui.updatePower(elapsed / maxCharge);
    }

    // XR input
    const rightGamepad = (world.input as any)?.xr?.gamepads?.right;
    if (rightGamepad) {
      const triggerDown = rightGamepad.getButtonDown?.(0); // Trigger
      const triggerUp = rightGamepad.getButtonUp?.(0);
      const triggerValue = rightGamepad.getButtonValue?.(0) ?? 0;
      const aDown = rightGamepad.getButtonDown?.(3); // A
      const bDown = rightGamepad.getButtonDown?.(4); // B

      if (game.state === GameState.Playing && !game.isAITurn()) {
        if (triggerDown && dartManager.canThrow()) {
          xrCharging = true;
          xrChargeStart = performance.now();
          ui.showPowerBar(true);
        }

        if (xrCharging) {
          const elapsed = Math.min(performance.now() - xrChargeStart, maxCharge);
          ui.updatePower(elapsed / maxCharge);

          if (triggerUp || triggerValue < 0.1) {
            const power = elapsed / maxCharge;
            // Use controller aim direction
            const spaces = (world as any).playerSpaceEntities;
            if (spaces?.raySpaces?.right) {
              const raySpace = spaces.raySpaces.right;
              const dir = new Vector3(0, 0, -1).applyQuaternion(raySpace.object3D.quaternion);
              const origin = raySpace.object3D.position.clone();

              // Intersect with board plane
              const t = (boardGroup.position.z - origin.z) / dir.z;
              if (t > 0) {
                const hitX = origin.x + dir.x * t - boardGroup.position.x;
                const hitY = origin.y + dir.y * t - boardGroup.position.y;
                dartManager.throwDart(hitX, hitY, power);
              }
            } else {
              // Fallback — aim at center
              dartManager.throwDart(0, 0, power);
            }
            xrCharging = false;
            ui.showPowerBar(false);
            ui.updatePower(0);
          }
        }
      }

      if (bDown) {
        if (game.state === GameState.Playing) {
          game.setState(GameState.Paused);
          ui.showPanel('pause');
        } else if (game.state === GameState.Paused) {
          game.setState(GameState.Playing);
          ui.showPanel('hud');
        }
      }
    }

    // Update effects
    effects.update(dt);

    // Update dart flight
    dartManager.update(dt);

    // Update UI animations
    ui.update(dt);

    requestAnimationFrame(update);
  }

  requestAnimationFrame(update);

  // Start with title screen
  game.setState(GameState.Title);
  ui.showPanel('title');
}

main().catch(console.error);

// Game state and logic for dart game modes
import { ScoreResult } from './dartboard';
import { StatsTracker } from './stats';
import { AchievementManager } from './achievements';
import { AudioManager } from './audio';

export enum GameMode {
  FiveOhOne = '501',
  Cricket = 'cricket',
  AroundTheClock = 'around-the-clock',
  Shanghai = 'shanghai',
}

export enum GameState {
  Title = 'title',
  ModeSelect = 'mode-select',
  DifficultySelect = 'difficulty-select',
  Playing = 'playing',
  Paused = 'paused',
  GameOver = 'gameover',
  Leaderboard = 'leaderboard',
  Achievements = 'achievements',
  Settings = 'settings',
  Help = 'help',
  Stats = 'stats',
}

export interface Player {
  name: string;
  score: number;
  isAI: boolean;
  // 501 specific
  remaining501?: number;
  // Cricket specific
  cricketMarks?: Record<number, number>; // segment -> marks (0-3)
  cricketPoints?: number;
  // Around the Clock specific
  currentTarget?: number;
  // Shanghai specific
  shanghaiRound?: number;
  shanghaiScore?: number;
}

export interface TurnHistory {
  player: number;
  throws: ScoreResult[];
  turnScore: number;
}

export class GameManager {
  state: GameState = GameState.Title;
  mode: GameMode = GameMode.FiveOhOne;
  players: Player[] = [];
  currentPlayer = 0;
  dartsThisRound = 0;
  round = 1;
  turnHistory: TurnHistory[] = [];
  currentTurnThrows: ScoreResult[] = [];
  turnScore = 0;
  maxRounds = 20; // for Shanghai
  vsAI = true;

  private stats: StatsTracker;
  private achievements: AchievementManager;
  private audio: AudioManager;

  constructor(stats: StatsTracker, achievements: AchievementManager, audio: AudioManager) {
    this.stats = stats;
    this.achievements = achievements;
    this.audio = audio;
  }

  setState(state: GameState) {
    this.state = state;
  }

  startGame(mode: GameMode, vsAI: boolean) {
    this.mode = mode;
    this.vsAI = vsAI;
    this.currentPlayer = 0;
    this.dartsThisRound = 0;
    this.round = 1;
    this.turnHistory = [];
    this.currentTurnThrows = [];
    this.turnScore = 0;

    // Initialize players
    this.players = [
      this.createPlayer('Player 1', false),
    ];
    if (vsAI) {
      this.players.push(this.createPlayer('CPU', true));
    } else {
      this.players.push(this.createPlayer('Player 2', false));
    }

    this.state = GameState.Playing;
    this.audio.playGameStart();
  }

  private createPlayer(name: string, isAI: boolean): Player {
    const player: Player = { name, score: 0, isAI };
    switch (this.mode) {
      case GameMode.FiveOhOne:
        player.remaining501 = 501;
        break;
      case GameMode.Cricket:
        player.cricketMarks = { 15: 0, 16: 0, 17: 0, 18: 0, 19: 0, 20: 0, 25: 0 };
        player.cricketPoints = 0;
        break;
      case GameMode.AroundTheClock:
        player.currentTarget = 1;
        break;
      case GameMode.Shanghai:
        player.shanghaiRound = 1;
        player.shanghaiScore = 0;
        break;
    }
    return player;
  }

  recordThrow(result: ScoreResult) {
    this.dartsThisRound++;
    this.currentTurnThrows.push(result);
    const player = this.players[this.currentPlayer];

    switch (this.mode) {
      case GameMode.FiveOhOne:
        this.handle501Throw(player, result);
        break;
      case GameMode.Cricket:
        this.handleCricketThrow(player, result);
        break;
      case GameMode.AroundTheClock:
        this.handleAroundTheClockThrow(player, result);
        break;
      case GameMode.Shanghai:
        this.handleShanghaiThrow(player, result);
        break;
    }
  }

  private handle501Throw(player: Player, result: ScoreResult) {
    if (result.total === 0) return;

    const newRemaining = (player.remaining501 || 0) - result.total;

    // Must finish on a double (or bullseye)
    if (newRemaining === 0 && (result.multiplier === 2 || result.segment === 25)) {
      player.remaining501 = 0;
      this.turnScore += result.total;
    } else if (newRemaining > 0) {
      player.remaining501 = newRemaining;
      this.turnScore += result.total;
    } else {
      // Bust — score goes back to what it was at the start of turn
      player.remaining501 = (player.remaining501 || 0) + this.turnScore;
      this.turnScore = 0;
      this.dartsThisRound = 3; // End turn early
    }
  }

  private handleCricketThrow(player: Player, result: ScoreResult) {
    const cricketNumbers = [15, 16, 17, 18, 19, 20, 25];
    if (!cricketNumbers.includes(result.segment)) return;

    const marks = player.cricketMarks!;
    const otherPlayer = this.players[1 - this.currentPlayer];
    const otherMarks = otherPlayer.cricketMarks!;

    const hitsToAdd = result.segment === 25 ? (result.multiplier === 2 ? 2 : 1) : result.multiplier;

    for (let i = 0; i < hitsToAdd; i++) {
      if (marks[result.segment] < 3) {
        marks[result.segment]++;
      } else if (otherMarks[result.segment] < 3) {
        // Score points if this number is open and opponent hasn't closed it
        player.cricketPoints = (player.cricketPoints || 0) + (result.segment === 25 ? 25 : result.segment);
      }
    }
  }

  private handleAroundTheClockThrow(player: Player, result: ScoreResult) {
    if (result.segment === player.currentTarget) {
      player.currentTarget = (player.currentTarget || 1) + 1;
      this.turnScore += result.total;
    }
  }

  private handleShanghaiThrow(player: Player, result: ScoreResult) {
    // In Shanghai, you can only score on the current round number
    if (result.segment === this.round) {
      player.shanghaiScore = (player.shanghaiScore || 0) + result.total;
      this.turnScore += result.total;
    }

    // Shanghai! — hit single, double, and triple of the current round in one turn
    const roundThrows = this.currentTurnThrows.filter(t => t.segment === this.round);
    const hasSingle = roundThrows.some(t => t.multiplier === 1);
    const hasDouble = roundThrows.some(t => t.multiplier === 2);
    const hasTriple = roundThrows.some(t => t.multiplier === 3);
    if (hasSingle && hasDouble && hasTriple) {
      // Instant win
      player.shanghaiScore = (player.shanghaiScore || 0) + 1000; // Big bonus
    }
  }

  endTurn() {
    this.turnHistory.push({
      player: this.currentPlayer,
      throws: [...this.currentTurnThrows],
      turnScore: this.turnScore,
    });

    this.currentTurnThrows = [];
    this.turnScore = 0;
    this.dartsThisRound = 0;

    // Switch players
    this.currentPlayer = 1 - this.currentPlayer;
    if (this.currentPlayer === 0) {
      this.round++;
    }
  }

  isAITurn(): boolean {
    return this.players[this.currentPlayer]?.isAI || false;
  }

  isGameOver(): boolean {
    switch (this.mode) {
      case GameMode.FiveOhOne:
        return this.players.some(p => p.remaining501 === 0);
      case GameMode.Cricket:
        return this.players.some(p => {
          const marks = p.cricketMarks!;
          return Object.values(marks).every(m => m >= 3);
        });
      case GameMode.AroundTheClock:
        return this.players.some(p => (p.currentTarget || 1) > 20);
      case GameMode.Shanghai:
        return this.round > this.maxRounds;
      default:
        return false;
    }
  }

  getWinner(): number {
    switch (this.mode) {
      case GameMode.FiveOhOne:
        if (this.players[0].remaining501 === 0) return 1;
        if (this.players[1].remaining501 === 0) return 2;
        return this.players[0].remaining501! < this.players[1].remaining501! ? 1 : 2;
      case GameMode.Cricket: {
        const p1Closed = Object.values(this.players[0].cricketMarks!).every(m => m >= 3);
        const p2Closed = Object.values(this.players[1].cricketMarks!).every(m => m >= 3);
        if (p1Closed && !p2Closed) return 1;
        if (p2Closed && !p1Closed) return 2;
        return (this.players[0].cricketPoints || 0) >= (this.players[1].cricketPoints || 0) ? 1 : 2;
      }
      case GameMode.AroundTheClock:
        return (this.players[0].currentTarget || 1) >= (this.players[1].currentTarget || 1) ? 1 : 2;
      case GameMode.Shanghai:
        return (this.players[0].shanghaiScore || 0) >= (this.players[1].shanghaiScore || 0) ? 1 : 2;
      default:
        return 1;
    }
  }

  getPlayerDisplay(playerIndex: number): string {
    const p = this.players[playerIndex];
    switch (this.mode) {
      case GameMode.FiveOhOne:
        return `${p.remaining501}`;
      case GameMode.Cricket:
        return `${p.cricketPoints || 0} pts`;
      case GameMode.AroundTheClock:
        return `Target: ${p.currentTarget}`;
      case GameMode.Shanghai:
        return `${p.shanghaiScore || 0}`;
      default:
        return '';
    }
  }

  getModeLabel(): string {
    switch (this.mode) {
      case GameMode.FiveOhOne: return '501';
      case GameMode.Cricket: return 'CRICKET';
      case GameMode.AroundTheClock: return 'AROUND THE CLOCK';
      case GameMode.Shanghai: return 'SHANGHAI';
    }
  }

  getRoundInfo(): string {
    switch (this.mode) {
      case GameMode.Shanghai:
        return `Round ${this.round} / ${this.maxRounds} (Target: ${this.round})`;
      default:
        return `Round ${this.round}`;
    }
  }
}

// Dartboard geometry and scoring
import {
  Group,
  Mesh,
  CylinderGeometry,
  RingGeometry,
  CircleGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  EdgesGeometry,
  LineSegments,
  LineBasicMaterial,
  DoubleSide,
  AdditiveBlending,
  Color,
  Vector3,
  BufferGeometry,
  Float32BufferAttribute,
  World,
} from '@iwsdk/core';

// Standard dartboard segment order (clockwise from top)
export const BOARD_SEGMENTS = [20, 1, 18, 4, 13, 6, 10, 15, 2, 17, 3, 19, 7, 16, 8, 11, 14, 9, 12, 5];

// Dartboard dimensions (in meters, scaled from standard 451mm diameter)
const BOARD_RADIUS = 0.2255; // 451mm / 2
const DOUBLE_OUTER = 0.170;
const DOUBLE_INNER = 0.162;
const TRIPLE_OUTER = 0.107;
const TRIPLE_INNER = 0.099;
const OUTER_BULL = 0.0159; // outer bull radius
const INNER_BULL = 0.00635; // bullseye radius
const WIRE_WIDTH = 0.001;

// Segment colors — alternating black/white with red/green accents
const SEGMENT_COLORS = {
  black: '#0a0a1a',
  white: '#1a1a2a',
  red: '#cc0033',
  green: '#009933',
  bullRed: '#cc0033',
  bullGreen: '#009933',
  wire: '#444466',
  surround: '#111122',
  neonCyan: '#00ffff',
  neonMagenta: '#ff00ff',
};

export interface ScoreResult {
  segment: number;   // 1-20, or 25 for bull
  multiplier: number; // 1=single, 2=double, 3=triple, 25=outer bull, 50=inner bull
  total: number;
  x: number;
  y: number;
  label: string;
}

export function getScoreForPosition(x: number, y: number): ScoreResult {
  const dist = Math.sqrt(x * x + y * y);
  let angle = Math.atan2(x, y); // Note: x,y not y,x — 20 is at top
  if (angle < 0) angle += Math.PI * 2;

  // Bullseye check
  if (dist <= INNER_BULL) {
    return { segment: 25, multiplier: 2, total: 50, x, y, label: 'BULLSEYE!' };
  }
  if (dist <= OUTER_BULL) {
    return { segment: 25, multiplier: 1, total: 25, x, y, label: 'BULL' };
  }

  // Off the board
  if (dist > BOARD_RADIUS) {
    return { segment: 0, multiplier: 0, total: 0, x, y, label: 'MISS' };
  }

  // Determine segment
  const segmentAngle = (Math.PI * 2) / 20;
  const halfSeg = segmentAngle / 2;
  // Adjust angle so segment 20 is centered at top (angle = 0)
  let adjustedAngle = angle + halfSeg;
  if (adjustedAngle >= Math.PI * 2) adjustedAngle -= Math.PI * 2;
  const segIndex = Math.floor(adjustedAngle / segmentAngle);
  const segment = BOARD_SEGMENTS[segIndex] || 20;

  // Determine ring
  let multiplier = 1;
  let label = `${segment}`;
  if (dist >= DOUBLE_INNER && dist <= DOUBLE_OUTER) {
    multiplier = 2;
    label = `D${segment}`;
  } else if (dist >= TRIPLE_INNER && dist <= TRIPLE_OUTER) {
    multiplier = 3;
    label = `T${segment}`;
  }

  return { segment, multiplier, total: segment * multiplier, x, y, label };
}

export function createDartboard(world: World): Group {
  const board = new Group();

  // Surround ring (dark background beyond scoring area)
  const surroundGeo = new RingGeometry(BOARD_RADIUS, BOARD_RADIUS + 0.04, 64);
  const surroundMat = new MeshStandardMaterial({
    color: SEGMENT_COLORS.surround,
    emissive: new Color(SEGMENT_COLORS.surround),
    emissiveIntensity: 0.3,
    side: DoubleSide,
  });
  const surround = new Mesh(surroundGeo, surroundMat);
  board.add(surround);

  // Outer frame — glowing neon ring
  const frameGeo = new RingGeometry(BOARD_RADIUS + 0.04, BOARD_RADIUS + 0.05, 64);
  const frameMat = new MeshBasicMaterial({
    color: SEGMENT_COLORS.neonCyan,
    transparent: true,
    opacity: 0.8,
    side: DoubleSide,
  });
  const frame = new Mesh(frameGeo, frameMat);
  board.add(frame);

  // Glow ring
  const glowGeo = new RingGeometry(BOARD_RADIUS + 0.05, BOARD_RADIUS + 0.08, 64);
  const glowMat = new MeshBasicMaterial({
    color: SEGMENT_COLORS.neonCyan,
    transparent: true,
    opacity: 0.2,
    blending: AdditiveBlending,
    side: DoubleSide,
  });
  const glow = new Mesh(glowGeo, glowMat);
  board.add(glow);

  // Draw 20 segments
  const segmentAngle = (Math.PI * 2) / 20;
  for (let i = 0; i < 20; i++) {
    const startAngle = i * segmentAngle - segmentAngle / 2 - Math.PI / 2;
    const isEven = i % 2 === 0;

    // Outer single (between double and triple)
    drawSegmentRing(board, DOUBLE_INNER, TRIPLE_OUTER, startAngle, segmentAngle,
      isEven ? SEGMENT_COLORS.black : SEGMENT_COLORS.white);

    // Inner single (between triple and bull)
    drawSegmentRing(board, TRIPLE_INNER, OUTER_BULL, startAngle, segmentAngle,
      isEven ? SEGMENT_COLORS.black : SEGMENT_COLORS.white);

    // Double ring
    drawSegmentRing(board, DOUBLE_OUTER, DOUBLE_INNER, startAngle, segmentAngle,
      isEven ? SEGMENT_COLORS.red : SEGMENT_COLORS.green);

    // Triple ring
    drawSegmentRing(board, TRIPLE_OUTER, TRIPLE_INNER, startAngle, segmentAngle,
      isEven ? SEGMENT_COLORS.red : SEGMENT_COLORS.green);

    // Single outer (between double and board edge)
    drawSegmentRing(board, BOARD_RADIUS, DOUBLE_OUTER, startAngle, segmentAngle,
      isEven ? SEGMENT_COLORS.black : SEGMENT_COLORS.white);

    // Segment number label positions
    const labelAngle = i * segmentAngle - Math.PI / 2;
    const labelDist = BOARD_RADIUS + 0.025;
    const labelX = Math.cos(labelAngle) * labelDist;
    const labelY = Math.sin(labelAngle) * labelDist;

    // Number indicator — small glowing sphere
    const numGeo = new CircleGeometry(0.008, 8);
    const numMat = new MeshBasicMaterial({
      color: '#ffffff',
      transparent: true,
      opacity: 0.7,
    });
    const numMesh = new Mesh(numGeo, numMat);
    numMesh.position.set(labelX, labelY, 0.001);
    board.add(numMesh);
  }

  // Outer bull
  const outerBullGeo = new CircleGeometry(OUTER_BULL, 32);
  const outerBullMat = new MeshStandardMaterial({
    color: SEGMENT_COLORS.bullGreen,
    emissive: new Color(SEGMENT_COLORS.bullGreen),
    emissiveIntensity: 0.5,
    side: DoubleSide,
  });
  const outerBull = new Mesh(outerBullGeo, outerBullMat);
  outerBull.position.z = 0.001;
  board.add(outerBull);

  // Inner bull (bullseye)
  const innerBullGeo = new CircleGeometry(INNER_BULL, 32);
  const innerBullMat = new MeshStandardMaterial({
    color: SEGMENT_COLORS.bullRed,
    emissive: new Color(SEGMENT_COLORS.bullRed),
    emissiveIntensity: 0.8,
    side: DoubleSide,
  });
  const innerBull = new Mesh(innerBullGeo, innerBullMat);
  innerBull.position.z = 0.002;
  board.add(innerBull);

  // Bullseye glow
  const bullGlowGeo = new CircleGeometry(INNER_BULL * 2, 32);
  const bullGlowMat = new MeshBasicMaterial({
    color: '#ff3333',
    transparent: true,
    opacity: 0.15,
    blending: AdditiveBlending,
    side: DoubleSide,
  });
  const bullGlow = new Mesh(bullGlowGeo, bullGlowMat);
  bullGlow.position.z = 0.003;
  board.add(bullGlow);

  // Wire rings
  drawWireRing(board, DOUBLE_OUTER);
  drawWireRing(board, DOUBLE_INNER);
  drawWireRing(board, TRIPLE_OUTER);
  drawWireRing(board, TRIPLE_INNER);
  drawWireRing(board, OUTER_BULL);
  drawWireRing(board, INNER_BULL);

  // Wire spokes (segment dividers)
  for (let i = 0; i < 20; i++) {
    const angle = i * segmentAngle - segmentAngle / 2 - Math.PI / 2;
    drawWireSpoke(board, angle, INNER_BULL, BOARD_RADIUS);
  }

  // Board backing (solid cylinder behind the face)
  const backGeo = new CylinderGeometry(BOARD_RADIUS + 0.04, BOARD_RADIUS + 0.04, 0.04, 64);
  const backMat = new MeshStandardMaterial({
    color: '#0a0a15',
    roughness: 0.9,
  });
  const back = new Mesh(backGeo, backMat);
  back.rotation.x = Math.PI / 2;
  back.position.z = -0.02;
  board.add(back);

  return board;
}

function drawSegmentRing(
  parent: Group, outerR: number, innerR: number,
  startAngle: number, arcAngle: number, color: string
) {
  const segments = 16;
  const geo = new RingGeometry(innerR, outerR, segments, 1, startAngle, arcAngle);
  const mat = new MeshStandardMaterial({
    color,
    emissive: new Color(color),
    emissiveIntensity: 0.3,
    side: DoubleSide,
    roughness: 0.7,
  });
  const mesh = new Mesh(geo, mat);
  mesh.position.z = 0.001;
  parent.add(mesh);
}

function drawWireRing(parent: Group, radius: number) {
  const segments = 64;
  const points: number[] = [];
  for (let i = 0; i <= segments; i++) {
    const a = (i / segments) * Math.PI * 2;
    points.push(Math.cos(a) * radius, Math.sin(a) * radius, 0.003);
  }
  const geo = new BufferGeometry();
  geo.setAttribute('position', new Float32BufferAttribute(points, 3));
  const mat = new LineBasicMaterial({ color: SEGMENT_COLORS.wire, transparent: true, opacity: 0.6 });
  const line = new LineSegments(geo, mat);
  // Convert to line loop manually
  const loopGeo = new BufferGeometry();
  const loopPts: number[] = [];
  for (let i = 0; i < segments; i++) {
    const a1 = (i / segments) * Math.PI * 2;
    const a2 = ((i + 1) / segments) * Math.PI * 2;
    loopPts.push(Math.cos(a1) * radius, Math.sin(a1) * radius, 0.003);
    loopPts.push(Math.cos(a2) * radius, Math.sin(a2) * radius, 0.003);
  }
  loopGeo.setAttribute('position', new Float32BufferAttribute(loopPts, 3));
  const loop = new LineSegments(loopGeo, mat);
  parent.add(loop);
}

function drawWireSpoke(parent: Group, angle: number, innerR: number, outerR: number) {
  const geo = new BufferGeometry();
  const pts = [
    Math.cos(angle) * innerR, Math.sin(angle) * innerR, 0.003,
    Math.cos(angle) * outerR, Math.sin(angle) * outerR, 0.003,
  ];
  geo.setAttribute('position', new Float32BufferAttribute(pts, 3));
  const mat = new LineBasicMaterial({ color: SEGMENT_COLORS.wire, transparent: true, opacity: 0.6 });
  parent.add(new LineSegments(geo, mat));
}

// Dart throwing and flight
import {
  World,
  Group,
  Mesh,
  CylinderGeometry,
  ConeGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  Color,
  Vector3,
  AdditiveBlending,
  BufferGeometry,
  Float32BufferAttribute,
  LineSegments,
  LineBasicMaterial,
} from '@iwsdk/core';

import { getScoreForPosition, ScoreResult } from './dartboard';
import { AudioManager } from './audio';
import { EffectsManager } from './effects';

interface Dart {
  group: Group;
  velocity: Vector3;
  state: 'flying' | 'stuck' | 'idle';
  trail: Vector3[];
  trailMesh: LineSegments | null;
}

export class DartManager {
  private world: World;
  private boardGroup: Group;
  private audio: AudioManager;
  private effects: EffectsManager;
  private darts: Dart[] = [];
  private maxDarts = 3;
  private throwCount = 0;

  public onDartHit: ((result: ScoreResult) => void) | null = null;

  constructor(world: World, boardGroup: Group, audio: AudioManager, effects: EffectsManager) {
    this.world = world;
    this.boardGroup = boardGroup;
    this.audio = audio;
    this.effects = effects;
  }

  canThrow(): boolean {
    return this.throwCount < this.maxDarts;
  }

  throwDart(aimX: number, aimY: number, power: number) {
    if (!this.canThrow()) return;

    // Add some natural scatter based on power (more power = more steady)
    const scatter = 0.015 * (1 - power * 0.5) + 0.005;
    const finalX = aimX + (Math.random() - 0.5) * scatter;
    const finalY = aimY + (Math.random() - 0.5) * scatter;

    // Create dart mesh
    const dart = this.createDartMesh();

    // Start from player position
    const startPos = new Vector3(0, 1.6, -0.3);
    dart.group.position.copy(startPos);
    this.world.scene.add(dart.group);

    // Calculate target on board
    const targetPos = new Vector3(
      this.boardGroup.position.x + finalX,
      this.boardGroup.position.y + finalY,
      this.boardGroup.position.z + 0.02
    );

    // Flight velocity — dart travels to board
    const direction = targetPos.clone().sub(startPos);
    const distance = direction.length();
    const flightTime = 0.15 + 0.15 * (1 - power); // faster throw = less time
    const speed = distance / flightTime;
    direction.normalize().multiplyScalar(speed);

    dart.velocity = direction;
    dart.state = 'flying';
    this.darts.push(dart);
    this.throwCount++;

    // Throw sound
    this.audio.playThrow(power);

    // Calculate score immediately for where it will land
    const result = getScoreForPosition(finalX, finalY);

    // Schedule hit after flight time
    setTimeout(() => {
      if (dart.state === 'flying') {
        dart.state = 'stuck';
        dart.group.position.copy(targetPos);
        dart.group.rotation.x = 0;
        dart.velocity.set(0, 0, 0);

        // Hit sound
        if (result.total > 0) {
          this.audio.playHit(result);
        } else {
          this.audio.playMiss();
        }

        if (this.onDartHit) {
          this.onDartHit(result);
        }
      }
    }, flightTime * 1000);
  }

  private createDartMesh(): Dart {
    const group = new Group();

    // Dart body (barrel) — glowing neon cylinder
    const barrelGeo = new CylinderGeometry(0.003, 0.004, 0.05, 8);
    const barrelMat = new MeshStandardMaterial({
      color: '#00ffff',
      emissive: new Color('#00ffff'),
      emissiveIntensity: 0.6,
      metalness: 0.8,
      roughness: 0.2,
    });
    const barrel = new Mesh(barrelGeo, barrelMat);
    barrel.rotation.x = Math.PI / 2;
    group.add(barrel);

    // Dart point (tip) — sharp cone
    const tipGeo = new ConeGeometry(0.003, 0.02, 8);
    const tipMat = new MeshStandardMaterial({
      color: '#ffffff',
      emissive: new Color('#ffffff'),
      emissiveIntensity: 0.4,
      metalness: 0.9,
    });
    const tip = new Mesh(tipGeo, tipMat);
    tip.rotation.x = -Math.PI / 2;
    tip.position.z = -0.035;
    group.add(tip);

    // Flights (fins) — flat panels
    for (let i = 0; i < 4; i++) {
      const flightGeo = new CylinderGeometry(0, 0.008, 0.02, 3);
      const flightMat = new MeshBasicMaterial({
        color: '#ff00ff',
        transparent: true,
        opacity: 0.7,
        side: 2, // DoubleSide
      });
      const flight = new Mesh(flightGeo, flightMat);
      flight.rotation.x = Math.PI / 2;
      flight.rotation.z = (i / 4) * Math.PI * 2;
      flight.position.z = 0.03;
      group.add(flight);
    }

    // Glow
    const glowGeo = new CylinderGeometry(0.008, 0.008, 0.06, 8);
    const glowMat = new MeshBasicMaterial({
      color: '#00ffff',
      transparent: true,
      opacity: 0.15,
      blending: AdditiveBlending,
    });
    const glowMesh = new Mesh(glowGeo, glowMat);
    glowMesh.rotation.x = Math.PI / 2;
    group.add(glowMesh);

    // Point toward -Z (board direction)
    group.rotation.x = 0;

    return {
      group,
      velocity: new Vector3(),
      state: 'idle',
      trail: [],
      trailMesh: null,
    };
  }

  update(dt: number) {
    for (const dart of this.darts) {
      if (dart.state === 'flying') {
        // Add slight gravity
        dart.velocity.y -= 0.5 * dt;

        // Move
        dart.group.position.add(dart.velocity.clone().multiplyScalar(dt));

        // Point dart in flight direction
        if (dart.velocity.lengthSq() > 0.01) {
          const dir = dart.velocity.clone().normalize();
          dart.group.lookAt(dart.group.position.clone().add(dir));
        }

        // Trail
        dart.trail.push(dart.group.position.clone());
        if (dart.trail.length > 20) dart.trail.shift();
        this.updateTrail(dart);

        // Bounds check — if dart goes past the board
        if (dart.group.position.z < -3) {
          dart.state = 'stuck';
          dart.velocity.set(0, 0, 0);
        }
      }
    }
  }

  private updateTrail(dart: Dart) {
    if (dart.trailMesh) {
      this.world.scene.remove(dart.trailMesh);
      dart.trailMesh.geometry.dispose();
    }

    if (dart.trail.length < 2) return;

    const pts: number[] = [];
    for (let i = 0; i < dart.trail.length - 1; i++) {
      pts.push(dart.trail[i].x, dart.trail[i].y, dart.trail[i].z);
      pts.push(dart.trail[i + 1].x, dart.trail[i + 1].y, dart.trail[i + 1].z);
    }
    const geo = new BufferGeometry();
    geo.setAttribute('position', new Float32BufferAttribute(pts, 3));
    const mat = new LineBasicMaterial({
      color: '#00ffff',
      transparent: true,
      opacity: 0.3,
    });
    dart.trailMesh = new LineSegments(geo, mat);
    this.world.scene.add(dart.trailMesh);
  }

  clearDarts() {
    for (const dart of this.darts) {
      this.world.scene.remove(dart.group);
      if (dart.trailMesh) {
        this.world.scene.remove(dart.trailMesh);
        dart.trailMesh.geometry.dispose();
      }
    }
    this.darts = [];
    this.throwCount = 0;
  }
}

// UI Manager — all spatial PanelUI panels
import {
  World,
  PanelUI,
  PanelDocument,
  UIKitDocument,
  Follower,
  FollowBehavior,
  ScreenSpace,
  Vector3,
  Entity,
} from '@iwsdk/core';

import { GameManager, GameMode, GameState } from './game';
import { DartManager } from './darts';
import { AudioManager } from './audio';
import { AchievementManager, Achievement } from './achievements';
import { StatsTracker } from './stats';
import { AIOpponent, AIDifficulty } from './ai';

type PanelName = 'title' | 'modeselect' | 'difficulty' | 'hud' | 'pause' | 'gameover' | 'leaderboard' | 'achievements' | 'settings' | 'help' | 'stats' | 'message' | 'power';

function setText(el: any, text: string) {
  if (!el) return;
  if (el.text && typeof el.text === 'object' && 'value' in el.text) {
    el.text.value = text;
  } else if ('innerText' in el) {
    el.innerText = text;
  }
}

export class UIManager {
  private world: World;
  private game: GameManager;
  private dartManager: DartManager;
  private audio: AudioManager;
  private achievements: AchievementManager;
  private stats: StatsTracker;
  private ai: AIOpponent;

  private panels: Map<PanelName, Entity> = new Map();
  private docs: Map<PanelName, UIKitDocument | null> = new Map();

  private messageTimer = 0;
  private currentPanel: PanelName | null = null;

  constructor(
    world: World, game: GameManager, dartManager: DartManager,
    audio: AudioManager, achievements: AchievementManager,
    stats: StatsTracker, ai: AIOpponent
  ) {
    this.world = world;
    this.game = game;
    this.dartManager = dartManager;
    this.audio = audio;
    this.achievements = achievements;
    this.stats = stats;
    this.ai = ai;

    this.createPanels();
    this.setupAchievementToast();
  }

  private createPanels() {
    // Title screen — world-space, floating in front of the board
    this.createPanel('title', '/ui/title.json', {
      position: new Vector3(0, 1.7, -1.5),
      maxWidth: 0.8,
      maxHeight: 1.0,
    });

    // Mode select
    this.createPanel('modeselect', '/ui/modeselect.json', {
      position: new Vector3(0, 1.7, -1.5),
      maxWidth: 0.8,
      maxHeight: 1.0,
    });

    // Difficulty select
    this.createPanel('difficulty', '/ui/difficulty.json', {
      position: new Vector3(0, 1.7, -1.5),
      maxWidth: 0.7,
      maxHeight: 0.8,
    });

    // HUD — head-following
    this.createPanel('hud', '/ui/hud.json', {
      follower: true,
      offsetPosition: [0.25, -0.12, -0.5] as [number, number, number],
      maxWidth: 0.3,
      maxHeight: 0.15,
    });

    // Power bar — head-following, bottom center
    this.createPanel('power', '/ui/power.json', {
      follower: true,
      offsetPosition: [0, -0.2, -0.5] as [number, number, number],
      maxWidth: 0.15,
      maxHeight: 0.04,
    });

    // Pause
    this.createPanel('pause', '/ui/pause.json', {
      position: new Vector3(0, 1.7, -1.2),
      maxWidth: 0.6,
      maxHeight: 0.6,
    });

    // Game over
    this.createPanel('gameover', '/ui/gameover.json', {
      position: new Vector3(0, 1.7, -1.5),
      maxWidth: 0.8,
      maxHeight: 0.8,
    });

    // Leaderboard
    this.createPanel('leaderboard', '/ui/leaderboard.json', {
      position: new Vector3(0, 1.7, -1.5),
      maxWidth: 0.8,
      maxHeight: 1.0,
    });

    // Achievements
    this.createPanel('achievements', '/ui/achievements.json', {
      position: new Vector3(0, 1.7, -1.5),
      maxWidth: 0.8,
      maxHeight: 1.0,
    });

    // Settings
    this.createPanel('settings', '/ui/settings.json', {
      position: new Vector3(0, 1.7, -1.5),
      maxWidth: 0.7,
      maxHeight: 0.9,
    });

    // Help
    this.createPanel('help', '/ui/help.json', {
      position: new Vector3(0, 1.7, -1.5),
      maxWidth: 0.8,
      maxHeight: 1.0,
    });

    // Stats
    this.createPanel('stats', '/ui/stats.json', {
      position: new Vector3(0, 1.7, -1.5),
      maxWidth: 0.8,
      maxHeight: 1.0,
    });

    // Message toast — head-following, top
    this.createPanel('message', '/ui/message.json', {
      follower: true,
      offsetPosition: [0, 0.1, -0.5] as [number, number, number],
      maxWidth: 0.3,
      maxHeight: 0.06,
    });
  }

  private createPanel(name: PanelName, config: string, opts: {
    position?: Vector3;
    follower?: boolean;
    offsetPosition?: [number, number, number];
    maxWidth: number;
    maxHeight: number;
  }) {
    const entity = this.world.createTransformEntity(undefined, { persistent: true });

    if (opts.position) {
      entity.object3D.position.copy(opts.position);
    }

    entity.addComponent(PanelUI, {
      config,
      maxWidth: opts.maxWidth,
      maxHeight: opts.maxHeight,
    });

    if (opts.follower) {
      entity.addComponent(Follower, {
        target: (this.world as any).player?.head,
        offsetPosition: opts.offsetPosition || [0, 0, -0.5],
        behavior: FollowBehavior.PivotY,
        speed: 5,
        tolerance: 0.3,
      });
    }

    // Hide initially
    entity.object3D.visible = false;
    this.panels.set(name, entity);
    this.docs.set(name, null);
  }

  private getDoc(name: PanelName): UIKitDocument | null {
    let doc = this.docs.get(name);
    if (doc) return doc;

    const entity = this.panels.get(name);
    if (!entity) return null;

    doc = entity.getValue(PanelDocument, 'document') as UIKitDocument | undefined ?? null;
    if (doc) {
      this.docs.set(name, doc);
      this.bindEvents(name, doc);
    }
    return doc;
  }

  private bindEvents(name: PanelName, doc: UIKitDocument) {
    switch (name) {
      case 'title': {
        doc.getElementById('btn-play')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.showPanel('modeselect');
        });
        doc.getElementById('btn-leaderboard')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.updateLeaderboard();
          this.showPanel('leaderboard');
        });
        doc.getElementById('btn-achievements')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.updateAchievements();
          this.showPanel('achievements');
        });
        doc.getElementById('btn-settings')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.showPanel('settings');
        });
        doc.getElementById('btn-help')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.showPanel('help');
        });
        doc.getElementById('btn-stats')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.updateStatsPanel();
          this.showPanel('stats');
        });
        break;
      }
      case 'modeselect': {
        doc.getElementById('btn-501')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.game.mode = GameMode.FiveOhOne;
          this.showPanel('difficulty');
        });
        doc.getElementById('btn-cricket')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.game.mode = GameMode.Cricket;
          this.showPanel('difficulty');
        });
        doc.getElementById('btn-around')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.game.mode = GameMode.AroundTheClock;
          this.showPanel('difficulty');
        });
        doc.getElementById('btn-shanghai')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.game.mode = GameMode.Shanghai;
          this.showPanel('difficulty');
        });
        doc.getElementById('btn-mode-back')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.showPanel('title');
        });
        break;
      }
      case 'difficulty': {
        doc.getElementById('btn-easy')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.ai.difficulty = AIDifficulty.Easy;
          this.game.startGame(this.game.mode, true);
          this.showPanel('hud');
        });
        doc.getElementById('btn-medium')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.ai.difficulty = AIDifficulty.Medium;
          this.game.startGame(this.game.mode, true);
          this.showPanel('hud');
        });
        doc.getElementById('btn-hard')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.ai.difficulty = AIDifficulty.Hard;
          this.game.startGame(this.game.mode, true);
          this.showPanel('hud');
        });
        doc.getElementById('btn-diff-back')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.showPanel('modeselect');
        });
        break;
      }
      case 'pause': {
        doc.getElementById('btn-resume')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.game.setState(GameState.Playing);
          this.showPanel('hud');
        });
        doc.getElementById('btn-quit')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.dartManager.clearDarts();
          this.game.setState(GameState.Title);
          this.showPanel('title');
        });
        break;
      }
      case 'gameover': {
        doc.getElementById('btn-rematch')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.dartManager.clearDarts();
          this.game.startGame(this.game.mode, this.game.vsAI);
          this.showPanel('hud');
        });
        doc.getElementById('btn-menu')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.dartManager.clearDarts();
          this.game.setState(GameState.Title);
          this.showPanel('title');
        });
        break;
      }
      case 'leaderboard':
      case 'achievements':
      case 'help':
      case 'stats': {
        doc.getElementById('btn-back')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.showPanel('title');
        });
        break;
      }
      case 'settings': {
        doc.getElementById('btn-master-up')?.addEventListener('click', () => {
          this.audio.setVolume('master', this.audio.masterVolume + 0.1);
          this.updateSettingsDisplay();
        });
        doc.getElementById('btn-master-down')?.addEventListener('click', () => {
          this.audio.setVolume('master', this.audio.masterVolume - 0.1);
          this.updateSettingsDisplay();
        });
        doc.getElementById('btn-sfx-up')?.addEventListener('click', () => {
          this.audio.setVolume('sfx', this.audio.sfxVolume + 0.1);
          this.updateSettingsDisplay();
        });
        doc.getElementById('btn-sfx-down')?.addEventListener('click', () => {
          this.audio.setVolume('sfx', this.audio.sfxVolume - 0.1);
          this.updateSettingsDisplay();
        });
        doc.getElementById('btn-music-up')?.addEventListener('click', () => {
          this.audio.setVolume('music', this.audio.musicVolume + 0.1);
          this.updateSettingsDisplay();
        });
        doc.getElementById('btn-music-down')?.addEventListener('click', () => {
          this.audio.setVolume('music', this.audio.musicVolume - 0.1);
          this.updateSettingsDisplay();
        });
        doc.getElementById('btn-settings-back')?.addEventListener('click', () => {
          this.audio.playButtonClick();
          this.showPanel('title');
        });
        break;
      }
    }
  }

  showPanel(name: PanelName | 'hud') {
    // Hide all non-HUD panels
    for (const [pName, entity] of this.panels) {
      if (pName === 'hud' || pName === 'power' || pName === 'message') continue;
      entity.object3D.visible = false;
    }

    if (name === 'hud') {
      // Show HUD only
      const hud = this.panels.get('hud');
      if (hud) hud.object3D.visible = true;
      this.updateGameState();
      this.currentPanel = 'hud';
      // Hide other panels
      for (const [pName, entity] of this.panels) {
        if (pName !== 'hud' && pName !== 'power' && pName !== 'message') {
          entity.object3D.visible = false;
        }
      }
    } else {
      // Hide HUD when showing menu panels
      const hud = this.panels.get('hud');
      if (hud) hud.object3D.visible = false;
      const power = this.panels.get('power');
      if (power) power.object3D.visible = false;

      const panel = this.panels.get(name);
      if (panel) panel.object3D.visible = true;
      this.currentPanel = name;

      // Update panel content
      if (name === 'gameover') this.updateGameOverPanel();
      if (name === 'settings') this.updateSettingsDisplay();
    }
  }

  showPowerBar(visible: boolean) {
    const power = this.panels.get('power');
    if (power) power.object3D.visible = visible;
  }

  updatePower(power: number) {
    const doc = this.getDoc('power');
    if (!doc) return;
    const bar = doc.getElementById('power-fill');
    const label = doc.getElementById('power-label');
    const pct = Math.round(power * 100);
    setText(label, `${pct}%`);
    // Update bar width visually by changing text
    const filled = Math.round(power * 10);
    const blocks = '\u2588'.repeat(filled) + '\u2591'.repeat(10 - filled);
    setText(bar, blocks);
  }

  updateGameState() {
    const doc = this.getDoc('hud');
    if (!doc) return;

    const mode = doc.getElementById('hud-mode');
    const player = doc.getElementById('hud-player');
    const score = doc.getElementById('hud-score');
    const round = doc.getElementById('hud-round');
    const darts = doc.getElementById('hud-darts');
    const turnScore = doc.getElementById('hud-turn');

    setText(mode, this.game.getModeLabel());
    setText(player, this.game.players[this.game.currentPlayer]?.name || '');
    setText(score, this.game.getPlayerDisplay(this.game.currentPlayer));
    setText(round, this.game.getRoundInfo());
    setText(darts, `Darts: ${3 - this.game.dartsThisRound}/3`);
    setText(turnScore, `Turn: ${this.game.turnScore}`);
  }

  private updateGameOverPanel() {
    const doc = this.getDoc('gameover');
    if (!doc) return;

    const winner = this.game.getWinner();
    const winnerName = this.game.players[winner - 1]?.name || 'Player';
    setText(doc.getElementById('go-winner'), `${winnerName} WINS!`);
    setText(doc.getElementById('go-mode'), this.game.getModeLabel());

    // Final scores
    const p1 = this.game.getPlayerDisplay(0);
    const p2 = this.game.getPlayerDisplay(1);
    setText(doc.getElementById('go-p1-score'), `${this.game.players[0]?.name}: ${p1}`);
    setText(doc.getElementById('go-p2-score'), `${this.game.players[1]?.name}: ${p2}`);
  }

  private updateLeaderboard() {
    // Leaderboard from localStorage
    const doc = this.getDoc('leaderboard');
    if (!doc) return;

    try {
      const saved = localStorage.getItem('neon-darts-leaderboard');
      const entries: { mode: string; winner: string; score: string; date: string }[] = saved ? JSON.parse(saved) : [];
      for (let i = 0; i < 10; i++) {
        const entry = entries[i];
        const el = doc.getElementById(`lb-${i}`);
        if (el && entry) {
          setText(el, `${i + 1}. ${entry.mode} - ${entry.winner} (${entry.score})`);
        } else if (el) {
          setText(el, `${i + 1}. ---`);
        }
      }
    } catch {}
  }

  private updateAchievements() {
    const doc = this.getDoc('achievements');
    if (!doc) return;

    setText(doc.getElementById('ach-count'),
      `${this.achievements.getUnlockedCount()} / ${this.achievements.getTotalCount()}`);

    for (let i = 0; i < this.achievements.achievements.length; i++) {
      const a = this.achievements.achievements[i];
      const el = doc.getElementById(`ach-${i}`);
      if (el) {
        setText(el, `${a.unlocked ? '[X]' : '[ ]'} ${a.name} - ${a.description}`);
      }
    }
  }

  private updateSettingsDisplay() {
    const doc = this.getDoc('settings');
    if (!doc) return;

    setText(doc.getElementById('vol-master'), `Master: ${Math.round(this.audio.masterVolume * 100)}%`);
    setText(doc.getElementById('vol-sfx'), `SFX: ${Math.round(this.audio.sfxVolume * 100)}%`);
    setText(doc.getElementById('vol-music'), `Music: ${Math.round(this.audio.musicVolume * 100)}%`);
  }

  private updateStatsPanel() {
    const doc = this.getDoc('stats');
    if (!doc) return;

    const s = this.stats.stats;
    setText(doc.getElementById('stat-games'), `Games Played: ${s.gamesPlayed}`);
    setText(doc.getElementById('stat-wins'), `Wins: ${s.gamesWon} (${this.stats.getWinRate()}%)`);
    setText(doc.getElementById('stat-darts'), `Darts Thrown: ${s.totalDartsThrown}`);
    setText(doc.getElementById('stat-accuracy'), `Accuracy: ${this.stats.getAccuracy()}%`);
    setText(doc.getElementById('stat-bullseyes'), `Bullseyes: ${s.bullseyes}`);
    setText(doc.getElementById('stat-triples'), `Triples: ${s.triples}`);
    setText(doc.getElementById('stat-doubles'), `Doubles: ${s.doubles}`);
    setText(doc.getElementById('stat-180s'), `180s: ${s.oneEighties}`);
    setText(doc.getElementById('stat-best-turn'), `Best Turn: ${s.highestSingleTurn}`);
    setText(doc.getElementById('stat-avg'), `Avg Turn: ${this.stats.getAverageScore()}`);
  }

  showMessage(text: string, duration = 2.0) {
    const panel = this.panels.get('message');
    if (panel) panel.object3D.visible = true;
    this.messageTimer = duration;

    const doc = this.getDoc('message');
    if (doc) setText(doc.getElementById('msg-text'), text);
  }

  private setupAchievementToast() {
    this.achievements.onUnlock = (achievement: Achievement) => {
      this.showMessage(`UNLOCKED: ${achievement.name}`, 3.0);
      this.audio.playAchievement();
    };
  }

  update(dt: number) {
    // Message timer
    if (this.messageTimer > 0) {
      this.messageTimer -= dt;
      if (this.messageTimer <= 0) {
        const panel = this.panels.get('message');
        if (panel) panel.object3D.visible = false;
      }
    }

    // Re-try getting docs for panels that haven't loaded yet
    for (const [name] of this.panels) {
      if (!this.docs.get(name as PanelName)) {
        this.getDoc(name as PanelName);
      }
    }
  }
}

// Audio manager — procedural Web Audio effects
export class AudioManager {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private sfxGain: GainNode | null = null;
  private musicGain: GainNode | null = null;
  private ambientOsc: OscillatorNode | null = null;
  private ambientLfo: OscillatorNode | null = null;

  masterVolume = 0.7;
  sfxVolume = 0.8;
  musicVolume = 0.3;

  private ensureContext() {
    if (!this.ctx) {
      this.ctx = new AudioContext();
      this.masterGain = this.ctx.createGain();
      this.masterGain.gain.value = this.masterVolume;
      this.masterGain.connect(this.ctx.destination);

      this.sfxGain = this.ctx.createGain();
      this.sfxGain.gain.value = this.sfxVolume;
      this.sfxGain.connect(this.masterGain);

      this.musicGain = this.ctx.createGain();
      this.musicGain.gain.value = this.musicVolume;
      this.musicGain.connect(this.masterGain);

      this.startAmbient();
    }
    if (this.ctx.state === 'suspended') this.ctx.resume();
    return this.ctx;
  }

  private startAmbient() {
    if (!this.ctx || !this.musicGain) return;

    // Deep ambient drone
    const osc = this.ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.value = 55;

    const lfo = this.ctx.createOscillator();
    lfo.type = 'sine';
    lfo.frequency.value = 0.2;
    const lfoGain = this.ctx.createGain();
    lfoGain.gain.value = 3;
    lfo.connect(lfoGain);
    lfoGain.connect(osc.frequency);
    lfo.start();

    // Pad
    const pad = this.ctx.createOscillator();
    pad.type = 'triangle';
    pad.frequency.value = 110;
    const padGain = this.ctx.createGain();
    padGain.gain.value = 0.08;
    pad.connect(padGain);
    padGain.connect(this.musicGain);
    pad.start();

    const oscGain = this.ctx.createGain();
    oscGain.gain.value = 0.12;
    osc.connect(oscGain);
    oscGain.connect(this.musicGain);
    osc.start();

    this.ambientOsc = osc;
    this.ambientLfo = lfo;
  }

  setVolume(type: 'master' | 'sfx' | 'music', value: number) {
    value = Math.max(0, Math.min(1, value));
    switch (type) {
      case 'master':
        this.masterVolume = value;
        if (this.masterGain) this.masterGain.gain.value = value;
        break;
      case 'sfx':
        this.sfxVolume = value;
        if (this.sfxGain) this.sfxGain.gain.value = value;
        break;
      case 'music':
        this.musicVolume = value;
        if (this.musicGain) this.musicGain.gain.value = value;
        break;
    }
  }

  playThrow(power: number) {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    // Whoosh — filtered noise
    const bufferSize = ctx.sampleRate * 0.15;
    const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = (Math.random() * 2 - 1) * (1 - i / bufferSize);
    }
    const src = ctx.createBufferSource();
    src.buffer = buffer;

    const filter = ctx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.value = 800 + power * 1200;
    filter.Q.value = 2;

    const gain = ctx.createGain();
    gain.gain.value = 0.3 + power * 0.3;
    gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.15);

    src.connect(filter);
    filter.connect(gain);
    gain.connect(this.sfxGain);
    src.start();
  }

  playHit(result: { total: number; multiplier: number; segment: number }) {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    // Thud/stick sound
    const osc = ctx.createOscillator();
    osc.type = 'square';
    osc.frequency.value = 200;
    osc.frequency.exponentialRampToValueAtTime(80, ctx.currentTime + 0.05);

    const gain = ctx.createGain();
    gain.gain.value = 0.4;
    gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.08);

    osc.connect(gain);
    gain.connect(this.sfxGain);
    osc.start();
    osc.stop(ctx.currentTime + 0.1);

    // Bonus chime for high scores
    if (result.multiplier >= 2 || result.segment === 25) {
      setTimeout(() => this.playScoreChime(result), 50);
    }
  }

  private playScoreChime(result: { total: number; multiplier: number; segment: number }) {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    const baseFreq = result.segment === 25 ? 880 : (result.multiplier === 3 ? 660 : 523);
    const notes = result.segment === 25 && result.multiplier === 2
      ? [baseFreq, baseFreq * 1.25, baseFreq * 1.5, baseFreq * 2]
      : [baseFreq, baseFreq * 1.25, baseFreq * 1.5];

    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = 'sine';
      osc.frequency.value = freq;

      const gain = ctx.createGain();
      gain.gain.value = 0;
      gain.gain.setValueAtTime(0, ctx.currentTime + i * 0.08);
      gain.gain.linearRampToValueAtTime(0.2, ctx.currentTime + i * 0.08 + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + i * 0.08 + 0.2);

      osc.connect(gain);
      gain.connect(this.sfxGain!);
      osc.start(ctx.currentTime + i * 0.08);
      osc.stop(ctx.currentTime + i * 0.08 + 0.25);
    });
  }

  playMiss() {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    // Dull thud
    const osc = ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.value = 100;
    osc.frequency.exponentialRampToValueAtTime(50, ctx.currentTime + 0.1);

    const gain = ctx.createGain();
    gain.gain.value = 0.3;
    gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.15);

    osc.connect(gain);
    gain.connect(this.sfxGain);
    osc.start();
    osc.stop(ctx.currentTime + 0.2);
  }

  playGameStart() {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    const notes = [262, 330, 392, 523];
    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = 'triangle';
      osc.frequency.value = freq;

      const gain = ctx.createGain();
      gain.gain.value = 0;
      gain.gain.setValueAtTime(0, ctx.currentTime + i * 0.1);
      gain.gain.linearRampToValueAtTime(0.15, ctx.currentTime + i * 0.1 + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + i * 0.1 + 0.3);

      osc.connect(gain);
      gain.connect(this.sfxGain!);
      osc.start(ctx.currentTime + i * 0.1);
      osc.stop(ctx.currentTime + i * 0.1 + 0.4);
    });
  }

  playGameOver(won: boolean) {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    if (won) {
      const notes = [523, 659, 784, 1047];
      notes.forEach((freq, i) => {
        const osc = ctx.createOscillator();
        osc.type = 'sawtooth';
        osc.frequency.value = freq;

        const filter = ctx.createBiquadFilter();
        filter.type = 'lowpass';
        filter.frequency.value = 2000;

        const gain = ctx.createGain();
        gain.gain.value = 0;
        gain.gain.setValueAtTime(0, ctx.currentTime + i * 0.12);
        gain.gain.linearRampToValueAtTime(0.12, ctx.currentTime + i * 0.12 + 0.03);
        gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + i * 0.12 + 0.5);

        osc.connect(filter);
        filter.connect(gain);
        gain.connect(this.sfxGain!);
        osc.start(ctx.currentTime + i * 0.12);
        osc.stop(ctx.currentTime + i * 0.12 + 0.6);
      });
    } else {
      const notes = [400, 350, 300, 200];
      notes.forEach((freq, i) => {
        const osc = ctx.createOscillator();
        osc.type = 'sine';
        osc.frequency.value = freq;

        const gain = ctx.createGain();
        gain.gain.value = 0;
        gain.gain.setValueAtTime(0, ctx.currentTime + i * 0.15);
        gain.gain.linearRampToValueAtTime(0.15, ctx.currentTime + i * 0.15 + 0.02);
        gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + i * 0.15 + 0.4);

        osc.connect(gain);
        gain.connect(this.sfxGain!);
        osc.start(ctx.currentTime + i * 0.15);
        osc.stop(ctx.currentTime + i * 0.15 + 0.5);
      });
    }
  }

  playAchievement() {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    const notes = [523, 659, 784, 1047, 1319];
    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = 'sine';
      osc.frequency.value = freq;

      const gain = ctx.createGain();
      gain.gain.value = 0;
      gain.gain.setValueAtTime(0, ctx.currentTime + i * 0.06);
      gain.gain.linearRampToValueAtTime(0.1, ctx.currentTime + i * 0.06 + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + i * 0.06 + 0.3);

      osc.connect(gain);
      gain.connect(this.sfxGain!);
      osc.start(ctx.currentTime + i * 0.06);
      osc.stop(ctx.currentTime + i * 0.06 + 0.35);
    });
  }

  playButtonClick() {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    const osc = ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.value = 600;

    const gain = ctx.createGain();
    gain.gain.value = 0.1;
    gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.05);

    osc.connect(gain);
    gain.connect(this.sfxGain);
    osc.start();
    osc.stop(ctx.currentTime + 0.06);
  }

  playTurnChange() {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    const osc = ctx.createOscillator();
    osc.type = 'triangle';
    osc.frequency.value = 440;

    const osc2 = ctx.createOscillator();
    osc2.type = 'triangle';
    osc2.frequency.value = 554;

    const gain = ctx.createGain();
    gain.gain.value = 0.08;
    gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.15);

    osc.connect(gain);
    osc2.connect(gain);
    gain.connect(this.sfxGain);
    osc.start();
    osc2.start(ctx.currentTime + 0.06);
    osc.stop(ctx.currentTime + 0.1);
    osc2.stop(ctx.currentTime + 0.16);
  }
}

// AI opponent logic
import { GameManager, GameMode } from './game';
import { BOARD_SEGMENTS } from './dartboard';

export enum AIDifficulty {
  Easy = 'easy',
  Medium = 'medium',
  Hard = 'hard',
}

interface TargetPosition {
  x: number;
  y: number;
}

export class AIOpponent {
  difficulty: AIDifficulty = AIDifficulty.Medium;

  private getNoiseAmount(): number {
    switch (this.difficulty) {
      case AIDifficulty.Easy: return 0.045;
      case AIDifficulty.Medium: return 0.025;
      case AIDifficulty.Hard: return 0.012;
    }
  }

  getTarget(game: GameManager): TargetPosition {
    switch (game.mode) {
      case GameMode.FiveOhOne:
        return this.get501Target(game);
      case GameMode.Cricket:
        return this.getCricketTarget(game);
      case GameMode.AroundTheClock:
        return this.getAroundTheClockTarget(game);
      case GameMode.Shanghai:
        return this.getShanghaiTarget(game);
      default:
        return { x: 0, y: 0 };
    }
  }

  private get501Target(game: GameManager): TargetPosition {
    const player = game.players[game.currentPlayer];
    const remaining = player.remaining501 || 0;

    // If can finish on a double
    if (remaining <= 40 && remaining % 2 === 0) {
      const doubleNeeded = remaining / 2;
      return this.getSegmentPosition(doubleNeeded, 'double');
    }

    // If remaining is 50 — aim for bullseye
    if (remaining === 50) {
      return { x: 0, y: 0 };
    }

    // Otherwise aim for high-value targets
    // T20 is the most efficient
    if (remaining > 60) {
      return this.getSegmentPosition(20, 'triple');
    }

    // Set up for a double finish
    const targetScore = remaining - (remaining % 2 === 0 ? remaining : remaining - 1);
    if (targetScore > 0 && targetScore <= 20) {
      return this.getSegmentPosition(targetScore, 'single');
    }

    return this.getSegmentPosition(20, 'triple');
  }

  private getCricketTarget(game: GameManager): TargetPosition {
    const player = game.players[game.currentPlayer];
    const marks = player.cricketMarks!;

    // Find unclosed numbers, prioritize higher numbers
    const cricketNums = [20, 19, 18, 17, 16, 15, 25];
    for (const num of cricketNums) {
      if (marks[num] < 3) {
        return num === 25
          ? { x: 0, y: 0 }
          : this.getSegmentPosition(num, 'triple');
      }
    }

    // All closed — aim for scoring on opponent's open numbers
    const opponent = game.players[1 - game.currentPlayer];
    const oppMarks = opponent.cricketMarks!;
    for (const num of cricketNums) {
      if (oppMarks[num] < 3) {
        return num === 25
          ? { x: 0, y: 0 }
          : this.getSegmentPosition(num, 'triple');
      }
    }

    return { x: 0, y: 0 };
  }

  private getAroundTheClockTarget(game: GameManager): TargetPosition {
    const player = game.players[game.currentPlayer];
    const target = player.currentTarget || 1;
    return this.getSegmentPosition(target, 'single');
  }

  private getShanghaiTarget(game: GameManager): TargetPosition {
    // Aim for triple of the current round number
    return this.getSegmentPosition(game.round, 'triple');
  }

  private getSegmentPosition(segment: number, ring: 'single' | 'double' | 'triple'): TargetPosition {
    if (segment === 25) {
      return { x: 0, y: 0 }; // Bullseye center
    }

    const segIndex = BOARD_SEGMENTS.indexOf(segment);
    if (segIndex === -1) return { x: 0, y: 0 };

    const segmentAngle = (Math.PI * 2) / 20;
    const angle = segIndex * segmentAngle - Math.PI / 2;

    let radius: number;
    switch (ring) {
      case 'double': radius = 0.166; break;
      case 'triple': radius = 0.103; break;
      default: radius = 0.135; break; // single (outer single area)
    }

    return {
      x: Math.cos(angle) * radius,
      y: Math.sin(angle) * radius,
    };
  }

  applyNoise(x: number, y: number): { x: number; y: number } {
    const noise = this.getNoiseAmount();
    return {
      x: x + (Math.random() - 0.5) * noise * 2,
      y: y + (Math.random() - 0.5) * noise * 2,
    };
  }
}

