    { id: 'cricket-closer', name: 'Cricket Closer', description: 'Win a game of Cricket', unlocked: false },
    { id: 'shanghai', name: 'Shanghai!', description: 'Hit single, double, and triple of same number in one turn', unlocked: false },
    { id: 'clock-master', name: 'Clock Master', description: 'Win Around the Clock', unlocked: false },
    { id: 'perfect-leg', name: 'Perfect Leg', description: 'Finish 501 in 9 darts or less', unlocked: false },
    { id: 'accuracy-80', name: 'Sharpshooter', description: 'Achieve 80%+ accuracy in a game', unlocked: false },
    { id: 'all-doubles', name: 'Double or Nothing', description: 'Hit all 20 doubles', unlocked: false },
    { id: 'hundred-games', name: 'Centurion', description: 'Play 100 games', unlocked: false },
    { id: 'ton-plus', name: 'Ton Plus', description: 'Score 100+ in a single turn', unlocked: false },
    { id: 'no-miss-turn', name: 'Precision', description: 'Complete 10 turns with no misses', unlocked: false },
    { id: 'triple-triple', name: 'Triple Threat', description: 'Hit 3 triples in one turn', unlocked: false },
    { id: 'beat-hard-ai', name: 'AI Slayer', description: 'Beat the Hard AI', unlocked: false },
    { id: 'all-modes', name: 'Versatile', description: 'Win in all 4 game modes', unlocked: false },
  ];

  private stats: StatsTracker;
  public onUnlock: ((achievement: Achievement) => void) | null = null;

  constructor(stats: StatsTracker) {
    this.stats = stats;
    this.load();
  }

  private load() {
    try {
      const saved = localStorage.getItem(ACHIEVEMENTS_KEY);
      if (saved) {
        const unlocked: string[] = JSON.parse(saved);
        for (const a of this.achievements) {
          a.unlocked = unlocked.includes(a.id);
        }
      }
    } catch {}
  }

  private save() {
    try {
      const unlocked = this.achievements.filter(a => a.unlocked).map(a => a.id);
      localStorage.setItem(ACHIEVEMENTS_KEY, JSON.stringify(unlocked));
    } catch {}
  }

  unlock(id: string) {
    const achievement = this.achievements.find(a => a.id === id);
    if (achievement && !achievement.unlocked) {
      achievement.unlocked = true;
      this.save();
      if (this.onUnlock) this.onUnlock(achievement);
    }
  }

  checkAll(game: GameManager, result: ScoreResult | null) {
    const s = this.stats.stats;

    // Throw-based
    if (result) {
      if (result.segment === 25 && result.multiplier === 2) this.unlock('bullseye');
      if (result.segment === 20 && result.multiplier === 3) this.unlock('triple-20');
      if (result.total >= 100) this.unlock('ton-plus');
    }

    // Turn-based
    if (game.currentTurnThrows.length === 3) {
      const turnTotal = game.currentTurnThrows.reduce((sum, t) => sum + t.total, 0);
      if (turnTotal === 180) this.unlock('one-eighty');
      if (turnTotal >= 100) this.unlock('ton-plus');

      const allBulls = game.currentTurnThrows.every(t => t.segment === 25 && t.multiplier === 2);
      if (allBulls) this.unlock('hat-trick');

      const allTriples = game.currentTurnThrows.every(t => t.multiplier === 3);
      if (allTriples) this.unlock('triple-triple');
    }

    // Game-based
    if (game.isGameOver()) {
      this.unlock('first-game');
      if (game.getWinner() === 1) {
        this.unlock('first-win');
        if (game.mode === GameMode.Cricket) this.unlock('cricket-closer');
        if (game.mode === GameMode.AroundTheClock) this.unlock('clock-master');
      }
    }

    // Stats-based
    if (s.gamesWon >= 5) this.unlock('five-wins');
    if (s.gamesWon >= 10) this.unlock('ten-wins');
    if (s.gamesPlayed >= 100) this.unlock('hundred-games');
    if (s.oneEighties > 0) this.unlock('one-eighty');

    // Check all modes won
    if (s.fiveOhOneWins > 0 && s.cricketWins > 0 && s.shanghaiWins > 0 && s.aroundTheClockWins > 0) {
      this.unlock('all-modes');
    }
  }

  getUnlockedCount(): number {
    return this.achievements.filter(a => a.unlocked).length;
  }

  getTotalCount(): number {
    return this.achievements.length;
  }
}

// Effects manager — particles, hit effects
import {
  World,
  Mesh,
  SphereGeometry,
  MeshBasicMaterial,
  Color,
  Vector3,
  AdditiveBlending,
  Group,
} from '@iwsdk/core';

interface Particle {
  mesh: Mesh;
  velocity: Vector3;
  life: number;
  maxLife: number;
}

const MAX_PARTICLES = 80;

export class EffectsManager {
  private world: World;
  private particles: Particle[] = [];
  private particleGroup: Group;
  private sharedGeo = new SphereGeometry(0.004, 4, 4);

  constructor(world: World) {
    this.world = world;
    this.particleGroup = new Group();
    world.scene.add(this.particleGroup);
  }

  spawnHitParticles(position: Vector3, color: string, count = 12) {
    for (let i = 0; i < count && this.particles.length < MAX_PARTICLES; i++) {
      const mat = new MeshBasicMaterial({
        color,
        transparent: true,
        opacity: 0.8,
        blending: AdditiveBlending,
      });
      const mesh = new Mesh(this.sharedGeo, mat);
      mesh.position.copy(position);
      this.particleGroup.add(mesh);

      const speed = 0.3 + Math.random() * 0.5;
      const angle = Math.random() * Math.PI * 2;
      const elevation = (Math.random() - 0.3) * Math.PI;

      this.particles.push({
        mesh,
        velocity: new Vector3(
          Math.cos(angle) * Math.cos(elevation) * speed,
          Math.sin(elevation) * speed + 0.2,
          Math.sin(angle) * Math.cos(elevation) * speed * 0.3
        ),
        life: 0.6 + Math.random() * 0.4,
        maxLife: 0.6 + Math.random() * 0.4,
      });
    }
  }

  update(dt: number) {
    for (let i = this.particles.length - 1; i >= 0; i--) {
      const p = this.particles[i];
      p.life -= dt;

      if (p.life <= 0) {
        this.particleGroup.remove(p.mesh);
        (p.mesh.material as MeshBasicMaterial).dispose();
        this.particles.splice(i, 1);
        continue;
      }

      p.velocity.y -= 1.5 * dt; // gravity
      p.mesh.position.add(p.velocity.clone().multiplyScalar(dt));

      const alpha = p.life / p.maxLife;
      (p.mesh.material as MeshBasicMaterial).opacity = alpha * 0.8;
    }
  }
}

// Statistics tracker
export interface GameStats {
  gamesPlayed: number;
  gamesWon: number;
  totalDartsThrown: number;
  bullseyes: number;
  triples: number;
  doubles: number;
  misses: number;
  highestSingleTurn: number;
  oneEighties: number; // 3x T20 = 180
  bestGameBy501: number; // least darts to finish
  cricketWins: number;
  shanghaiWins: number;
  aroundTheClockWins: number;
  fiveOhOneWins: number;
  totalScore: number;
  perfectLegs: number; // 501 in 9 darts or less
}

const STATS_KEY = 'neon-darts-stats';

export class StatsTracker {
  stats: GameStats;

  constructor() {
    this.stats = this.load();
  }

  private load(): GameStats {
    try {
      const saved = localStorage.getItem(STATS_KEY);
      if (saved) return JSON.parse(saved);
    } catch {}
    return {
      gamesPlayed: 0,
      gamesWon: 0,
      totalDartsThrown: 0,
      bullseyes: 0,
      triples: 0,
      doubles: 0,
      misses: 0,
      highestSingleTurn: 0,
      oneEighties: 0,
      bestGameBy501: 999,
      cricketWins: 0,
      shanghaiWins: 0,
      aroundTheClockWins: 0,
      fiveOhOneWins: 0,
      totalScore: 0,
      perfectLegs: 0,
    };
  }

  save() {
    try {
      localStorage.setItem(STATS_KEY, JSON.stringify(this.stats));
    } catch {}
  }

  recordThrow(total: number, multiplier: number, segment: number) {
    this.stats.totalDartsThrown++;
    this.stats.totalScore += total;
    if (total === 0) this.stats.misses++;
    if (segment === 25 && multiplier === 2) this.stats.bullseyes++;
    if (multiplier === 3) this.stats.triples++;
    if (multiplier === 2 && segment !== 25) this.stats.doubles++;
    this.save();
  }

  recordTurn(turnScore: number) {
    if (turnScore > this.stats.highestSingleTurn) {
      this.stats.highestSingleTurn = turnScore;
    }
    if (turnScore === 180) this.stats.oneEighties++;
    this.save();
  }

  recordGame(mode: string, won: boolean) {
    this.stats.gamesPlayed++;
    if (won) {
      this.stats.gamesWon++;
      switch (mode) {
        case '501': this.stats.fiveOhOneWins++; break;
        case 'cricket': this.stats.cricketWins++; break;
        case 'shanghai': this.stats.shanghaiWins++; break;
        case 'around-the-clock': this.stats.aroundTheClockWins++; break;
      }
    }
    this.save();
  }

  getWinRate(): number {
    if (this.stats.gamesPlayed === 0) return 0;
    return Math.round((this.stats.gamesWon / this.stats.gamesPlayed) * 100);
  }

  getAccuracy(): number {
    if (this.stats.totalDartsThrown === 0) return 0;
    const hits = this.stats.totalDartsThrown - this.stats.misses;
    return Math.round((hits / this.stats.totalDartsThrown) * 100);
  }

  getAverageScore(): number {
    if (this.stats.totalDartsThrown === 0) return 0;
    return Math.round((this.stats.totalScore / this.stats.totalDartsThrown) * 3); // per turn
  }
}

// Holodeck environment
import {
  World,
  Mesh,
  Group,
  PlaneGeometry,
  BoxGeometry,
  SphereGeometry,
  TorusGeometry,
  ConeGeometry,
  CylinderGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  EdgesGeometry,
  LineSegments,
  LineBasicMaterial,
  Color,
  Fog,
  AmbientLight,
  PointLight,
  DirectionalLight,
  DoubleSide,
  AdditiveBlending,
  MathUtils,
  Vector3,
} from '@iwsdk/core';

export function createEnvironment(world: World) {
  // Fog
  world.scene.fog = new Fog(0x000011, 5, 30);

  // Ambient light
  const ambient = new AmbientLight(0x222244, 0.5);
  world.scene.add(ambient);

  // Key lights
  const keyLight = new DirectionalLight(0x88aaff, 0.3);
  keyLight.position.set(2, 4, 1);
  world.scene.add(keyLight);

  // Board spotlight
  const boardLight = new PointLight(0x00ffff, 2, 5);
  boardLight.position.set(0, 2.5, -2.2);
  world.scene.add(boardLight);

  const boardLight2 = new PointLight(0xff00ff, 1, 4);
  boardLight2.position.set(-1, 2, -2);
  world.scene.add(boardLight2);

  const boardLight3 = new PointLight(0x00ff88, 1, 4);
  boardLight3.position.set(1, 2, -2);
  world.scene.add(boardLight3);

  // Neon grid floor
  const floorGeo = new PlaneGeometry(30, 30);
  const floorMat = new MeshStandardMaterial({
    color: '#050510',
    emissive: new Color('#050510'),
    emissiveIntensity: 0.2,
    roughness: 0.9,
    side: DoubleSide,
  });
  const floor = new Mesh(floorGeo, floorMat);
  floor.rotation.x = -Math.PI / 2;
  floor.position.y = 0;
  world.scene.add(floor);

  // Grid lines on floor
  const gridGroup = new Group();
  const gridMat = new LineBasicMaterial({ color: '#00ffff', transparent: true, opacity: 0.1 });
  for (let i = -15; i <= 15; i++) {
    const geo = new BoxGeometry(0.002, 0.001, 30);
    const mat = new MeshBasicMaterial({ color: '#00ffff', transparent: true, opacity: 0.08 });
    const line = new Mesh(geo, mat);
    line.position.set(i, 0.001, 0);
    gridGroup.add(line);

    const line2 = new Mesh(geo.clone(), mat);
    line2.rotation.y = Math.PI / 2;
    line2.position.set(0, 0.001, i);
    gridGroup.add(line2);
  }
  world.scene.add(gridGroup);

  // Neon grid ceiling
  const ceilGeo = new PlaneGeometry(30, 30);
  const ceilMat = new MeshStandardMaterial({
    color: '#020208',
    emissive: new Color('#020208'),
    emissiveIntensity: 0.1,
    side: DoubleSide,
  });
  const ceiling = new Mesh(ceilGeo, ceilMat);
  ceiling.rotation.x = Math.PI / 2;
  ceiling.position.y = 4;
  world.scene.add(ceiling);

  // Ceiling grid
  const ceilGridGroup = new Group();
  for (let i = -15; i <= 15; i += 2) {
    const geo = new BoxGeometry(0.002, 0.001, 30);
    const mat = new MeshBasicMaterial({ color: '#0088ff', transparent: true, opacity: 0.05 });
    const line = new Mesh(geo, mat);
    line.position.set(i, 3.999, 0);
    ceilGridGroup.add(line);

    const line2 = new Mesh(geo.clone(), mat);
    line2.rotation.y = Math.PI / 2;
    line2.position.set(0, 3.999, i);
    ceilGridGroup.add(line2);
  }
  world.scene.add(ceilGridGroup);

  // Back wall behind dartboard
  const wallGeo = new PlaneGeometry(6, 4);
  const wallMat = new MeshStandardMaterial({
    color: '#060612',
    emissive: new Color('#060612'),
    emissiveIntensity: 0.2,
    side: DoubleSide,
  });
  const wall = new Mesh(wallGeo, wallMat);
  wall.position.set(0, 2, -2.5);
  world.scene.add(wall);

  // Wall border glow
  const wallBorderGeo = new BoxGeometry(6.05, 4.05, 0.01);
  const wallBorderMat = new MeshBasicMaterial({
    color: '#00ffff',
    transparent: true,
    opacity: 0.15,
    blending: AdditiveBlending,
  });
  const wallBorder = new Mesh(wallBorderGeo, wallBorderMat);
  wallBorder.position.set(0, 2, -2.49);
  world.scene.add(wallBorder);

  // Throw line (oche) — glowing line on the floor
  const ocheGeo = new BoxGeometry(0.6, 0.005, 0.02);
  const ocheMat = new MeshBasicMaterial({
    color: '#ff00ff',
    transparent: true,
    opacity: 0.8,
  });
  const oche = new Mesh(ocheGeo, ocheMat);
  oche.position.set(0, 0.003, -0.01);
  world.scene.add(oche);

  // Oche glow
  const ocheGlowGeo = new BoxGeometry(0.65, 0.005, 0.06);
  const ocheGlowMat = new MeshBasicMaterial({
    color: '#ff00ff',
    transparent: true,
    opacity: 0.15,
    blending: AdditiveBlending,
  });
  const ocheGlow = new Mesh(ocheGlowGeo, ocheGlowMat);
  ocheGlow.position.set(0, 0.002, -0.01);
  world.scene.add(ocheGlow);

  // Floating wireframe decorations
  const decorations: { mesh: Mesh; speed: number; axis: Vector3 }[] = [];
  const decoTypes = [
    () => new TorusGeometry(0.15, 0.03, 8, 16),
    () => new BoxGeometry(0.2, 0.2, 0.2),
    () => new SphereGeometry(0.12, 8, 8),
    () => new ConeGeometry(0.12, 0.25, 6),
  ];
  const decoColors = ['#00ffff', '#ff00ff', '#00ff88', '#ffff00', '#ff6600'];

  for (let i = 0; i < 16; i++) {
    const geoFn = decoTypes[i % decoTypes.length];
    const geo = geoFn();
    const color = decoColors[i % decoColors.length];
    const edges = new EdgesGeometry(geo);
    const mat = new LineBasicMaterial({ color, transparent: true, opacity: 0.3 });
    const wireframe = new LineSegments(edges, mat) as any as Mesh;

    const x = (Math.random() - 0.5) * 12;
    const y = 0.5 + Math.random() * 3;
    const z = -5 + Math.random() * 8;
    wireframe.position.set(x, y, z);

    world.scene.add(wireframe);
  }

  // Ambient floating particles
  const particleGroup = new Group();
  for (let i = 0; i < 50; i++) {
    const geo = new SphereGeometry(0.005, 4, 4);
    const color = decoColors[i % decoColors.length];
    const mat = new MeshBasicMaterial({
      color,
      transparent: true,
      opacity: 0.3 + Math.random() * 0.3,
    });
    const particle = new Mesh(geo, mat);
    particle.position.set(
      (Math.random() - 0.5) * 15,
      Math.random() * 4,
      (Math.random() - 0.5) * 15
    );
    particleGroup.add(particle);
  }
  world.scene.add(particleGroup);

  // Side pillars for atmosphere
  for (let side = -1; side <= 1; side += 2) {
    const pillarGeo = new CylinderGeometry(0.05, 0.05, 4, 8);
    const pillarMat = new MeshStandardMaterial({
      color: '#111122',
      emissive: new Color('#00ffff'),
      emissiveIntensity: 0.1,
    });
    const pillar = new Mesh(pillarGeo, pillarMat);
    pillar.position.set(side * 1.5, 2, -2.5);
    world.scene.add(pillar);

    // Pillar top glow
    const topGeo = new SphereGeometry(0.08, 8, 8);
    const topMat = new MeshBasicMaterial({
      color: '#00ffff',
      transparent: true,
      opacity: 0.4,
    });
    const topGlow = new Mesh(topGeo, topMat);
    topGlow.position.set(side * 1.5, 4, -2.5);
    world.scene.add(topGlow);
  }
}

